use std::process::Command;

fn main() {
    // On WASM targets, provide a stub for __wasi_init_tp to prevent the
    // wasm-component-ld linker from failing. When C++ code (tree-sitter
    // grammars) links libc++, it keeps the crt1-command.o reference to
    // env::__wasi_init_tp alive, which wasm-component-ld cannot map to a
    // WASI component interface. A no-op stub satisfies the linker since we
    // don't use threading.
    let target = std::env::var("TARGET").unwrap_or_default();
    if target.contains("wasm") {
        let out_dir = std::env::var("OUT_DIR").unwrap();
        let stub_path = std::path::Path::new(&out_dir).join("wasi_tp_stub.c");
        std::fs::write(&stub_path, "void __wasi_init_tp(void) {}\n").unwrap();
        cc::Build::new().file(&stub_path).compile("wasi_tp_stub");
    }

    // Git commit hash
    let git_hash = Command::new("git")
        .args(["rev-parse", "--short", "HEAD"])
        .output()
        .ok()
        .filter(|o| o.status.success())
        .map(|o| String::from_utf8_lossy(&o.stdout).trim().to_string())
        .unwrap_or_else(|| "unknown".to_string());

    // Git dirty flag
    let git_dirty = Command::new("git")
        .args(["status", "--porcelain"])
        .output()
        .ok()
        .filter(|o| o.status.success())
        .map(|o| if o.stdout.is_empty() { "" } else { "-dirty" })
        .unwrap_or("");

    // Rerun if the release tag changes
    println!("cargo:rerun-if-env-changed=FV_RELEASE_TAG");

    // Version: prefer FV_RELEASE_TAG (set by CI from git tag), fall back to Cargo.toml
    let version = std::env::var("FV_RELEASE_TAG")
        .ok()
        .map(|t| t.strip_prefix('v').unwrap_or(&t).to_string())
        .unwrap_or_else(|| std::env::var("CARGO_PKG_VERSION").unwrap_or_default());

    println!("cargo:rustc-env=FV_VERSION={version}");
    println!("cargo:rustc-env=FV_GIT_SHA={git_hash}{git_dirty}");
    println!(
        "cargo:rustc-env=FV_BUILD_TARGET={}",
        std::env::var("TARGET").unwrap_or_default()
    );
    println!(
        "cargo:rustc-env=FV_BUILD_PROFILE={}",
        std::env::var("PROFILE").unwrap_or_default()
    );
}

//! Fuzz config loading from arbitrary YAML content.
//!
//! Target: Config deserialization, parsed_blacklist, parsed_whitelist

#![no_main]

use libfuzzer_sys::fuzz_target;
use std::fs;
use tempfile::TempDir;

fuzz_target!(|data: &[u8]| {
    if let Ok(yaml_content) = std::str::from_utf8(data) {
        // Limit input size
        if yaml_content.len() > 50_000 {
            return;
        }

        let temp_dir = match TempDir::new() {
            Ok(d) => d,
            Err(_) => return,
        };

        let config_path = temp_dir.path().join(".funveil_config");
        if fs::write(&config_path, yaml_content).is_err() {
            return;
        }

        // Config::load should never panic on malformed YAML
        if let Ok(config) = funveil::config::Config::load(temp_dir.path()) {
            // Parsing blacklist/whitelist entries should never panic
            let _ = config.parsed_blacklist();
            let _ = config.parsed_whitelist();

            // Querying veiled status should never panic
            let _ = config.is_veiled("test.rs", 1);
            let _ = config.veiled_ranges("test.rs");
        }
    }
});

//! Fuzz the unified/git diff patch parser with arbitrary input.
//!
//! Targets: PatchParser::parse_patch, PatchParser::detect_format

#![no_main]

use libfuzzer_sys::fuzz_target;

fuzz_target!(|data: &[u8]| {
    if let Ok(input) = std::str::from_utf8(data) {
        // Should never panic regardless of input
        let _ = funveil::patch::parser::PatchParser::parse_patch(input);
        let _ = funveil::patch::parser::PatchParser::detect_format(input);
    }
});

//! Fuzz the tree-sitter parser with arbitrary source code across all languages.
//!
//! Target: TreeSitterParser::parse_file

#![no_main]

use libfuzzer_sys::fuzz_target;
use std::path::PathBuf;

fuzz_target!(|data: &[u8]| {
    if let Ok(content) = std::str::from_utf8(data) {
        // Limit input size to avoid timeouts on pathological inputs
        if content.len() > 10_000 {
            return;
        }

        let parser = match funveil::parser::TreeSitterParser::new() {
            Ok(p) => p,
            Err(_) => return,
        };

        // Try parsing as each supported language
        let extensions = [
            "rs", "ts", "tsx", "py", "sh", "go", "zig", "html", "css", "xml", "md", "tf",
            "yaml", "yml",
        ];

        for ext in &extensions {
            let path = PathBuf::from(format!("fuzz_input.{ext}"));
            // Should never panic regardless of content
            let _ = parser.parse_file(&path, content);
        }
    }
});

//! Fuzz core type parsing and validation.
//!
//! Targets: ContentHash::from_string, ConfigEntry::parse, Pattern::from_regex,
//!          LineRange::new, LineRange::from_str

#![no_main]

use libfuzzer_sys::fuzz_target;
use std::str::FromStr;

fuzz_target!(|data: &[u8]| {
    if let Ok(input) = std::str::from_utf8(data) {
        // ContentHash validation — should never panic
        let _ = funveil::types::ContentHash::from_string(input.to_string());

        // ConfigEntry parsing — should never panic
        let _ = funveil::types::ConfigEntry::parse(input);

        // Pattern::from_regex — should never panic (even on pathological regexes)
        let _ = funveil::types::Pattern::from_regex(input);

        // LineRange from string — should never panic
        let _ = funveil::types::LineRange::from_str(input);

        // LineRange with arbitrary bounds
        if input.len() >= 8 {
            let bytes = input.as_bytes();
            let start = u32::from_le_bytes([bytes[0], bytes[1], bytes[2], bytes[3]]) as usize;
            let end = u32::from_le_bytes([bytes[4], bytes[5], bytes[6], bytes[7]]) as usize;
            let _ = funveil::types::LineRange::new(start, end);
        }
    }
});

//! Fuzz the veil/unveil roundtrip with arbitrary file content and range specs.
//!
//! Verifies that veil -> unveil produces the original content (or returns an error).

#![no_main]

use arbitrary::Arbitrary;
use libfuzzer_sys::fuzz_target;
use std::fs;
use tempfile::TempDir;

#[derive(Arbitrary, Debug)]
struct VeilInput {
    /// File content to veil
    content: String,
    /// Whether to do a partial veil
    partial: bool,
    /// Range start (1-indexed) for partial veils
    range_start: u8,
    /// Range end (1-indexed) for partial veils
    range_end: u8,
}

fuzz_target!(|input: VeilInput| {
    // Limit content size and skip empty
    if input.content.is_empty() || input.content.len() > 10_000 {
        return;
    }

    // Skip content with control characters (validate_filename would reject)
    if input.content.bytes().any(|b| b < 0x09 || (b > 0x0d && b < 0x20)) {
        return;
    }

    let temp_dir = match TempDir::new() {
        Ok(d) => d,
        Err(_) => return,
    };

    // Initialize funveil project
    let root = temp_dir.path();
    let data_dir = root.join(".funveil");
    let cas_dir = data_dir.join("objects");
    if fs::create_dir_all(&cas_dir).is_err() {
        return;
    }

    let mut config = match funveil::config::Config::load(root) {
        Ok(c) => c,
        Err(_) => return,
    };

    // Write test file
    let file_name = "fuzz_test.txt";
    let file_path = root.join(file_name);
    if fs::write(&file_path, &input.content).is_err() {
        return;
    }

    // Build ranges for partial veil
    let ranges = if input.partial {
        let start = (input.range_start as usize).max(1);
        let end = (input.range_end as usize).max(start);
        match funveil::types::LineRange::new(start, end) {
            Ok(r) => Some(vec![r]),
            Err(_) => None,
        }
    } else {
        None
    };

    let range_slice = ranges.as_deref();

    // Veil the file
    let veil_result = funveil::veil_file(root, &mut config, file_name, range_slice, true);
    if veil_result.is_err() {
        return; // Errors are acceptable — panics are not
    }
    let _ = config.save(root);

    // Unveil the file
    let unveil_result = funveil::unveil_file(root, &mut config, file_name, range_slice, true);
    if unveil_result.is_err() {
        return; // Errors are acceptable — panics are not
    }
    let _ = config.save(root);

    // For full veils, verify roundtrip produces original content
    if !input.partial {
        if let Ok(restored) = fs::read_to_string(&file_path) {
            assert_eq!(
                restored, input.content,
                "Full veil roundtrip lost data"
            );
        }
    }
});

