        // PartialRestore error should reflect the correct counts.
        let (temp, _) = setup();
        let cp_dir = temp.path().join(CHECKPOINTS_DIR).join("counter_cp");
        fs::create_dir_all(&cp_dir).unwrap();

        let store = ContentStore::new(temp.path());
