use std::fs;
use std::io;
use std::path::Path;

/// Saved permission state, to be restored on error.
pub struct SavedPerms {
    #[cfg(unix)]
    mode: u32,
    #[cfg(not(unix))]
    readonly: bool,
}

/// Save current permissions and make the file writable.
pub fn save_and_make_writable(path: &Path) -> io::Result<SavedPerms> {
    let metadata = fs::metadata(path)?;
    let mut perms = metadata.permissions();

    #[cfg(unix)]
    {
        use std::os::unix::fs::PermissionsExt;
        let saved = SavedPerms { mode: perms.mode() };
        perms.set_mode(0o644);
        fs::set_permissions(path, perms)?;
        Ok(saved)
    }

    #[cfg(not(unix))]
    {
        let saved = SavedPerms {
            readonly: perms.readonly(),
        };
        perms.set_readonly(false);
        fs::set_permissions(path, perms)?;
        Ok(saved)
    }
}

/// Restore previously saved permissions.
pub fn restore(path: &Path, saved: &SavedPerms) -> io::Result<()> {
    if let Ok(md) = fs::metadata(path) {
        let mut p = md.permissions();

        #[cfg(unix)]
        {
            use std::os::unix::fs::PermissionsExt;
            p.set_mode(saved.mode);
        }

        #[cfg(not(unix))]
        {
            p.set_readonly(saved.readonly);
        }

        fs::set_permissions(path, p)?;
    }
    Ok(())
}

/// Set a file to read-only.
pub fn set_readonly(path: &Path) -> io::Result<()> {
    let mut perms = fs::metadata(path)?.permissions();
    perms.set_readonly(true);
    fs::set_permissions(path, perms)
}

/// Set a file's Unix mode. No-op on non-Unix.
#[cfg(unix)]
pub fn set_mode(path: &Path, mode: u32) -> io::Result<()> {
    use std::os::unix::fs::PermissionsExt;
    let mut perms = fs::metadata(path)?.permissions();
    perms.set_mode(mode);
    fs::set_permissions(path, perms)
}

#[cfg(not(unix))]
pub fn set_mode(_path: &Path, _mode: u32) -> io::Result<()> {
    Ok(())
}

/// Get the Unix mode bits from file metadata. Returns 0o644 on non-Unix.
#[cfg(unix)]
pub fn file_mode(metadata: &fs::Metadata) -> u32 {
    use std::os::unix::fs::MetadataExt;
    metadata.mode()
}

#[cfg(not(unix))]
pub fn file_mode(_metadata: &fs::Metadata) -> u32 {
    0o644
}

/// Parse an octal permission string, defaulting to 0o644.
pub fn parse_mode(octal_str: &str) -> u32 {
    u32::from_str_radix(octal_str, 8).unwrap_or(0o644)
}

/// Format a mode as an octal string.
pub fn format_mode(mode: u32) -> String {
    format!("{mode:o}")
}

#[cfg(test)]
mod tests {
    use super::*;
    use tempfile::TempDir;

    #[test]
    fn test_parse_mode_valid() {
        assert_eq!(parse_mode("644"), 0o644);
        assert_eq!(parse_mode("755"), 0o755);
        assert_eq!(parse_mode("600"), 0o600);
    }

    #[test]
    fn test_parse_mode_invalid() {
        assert_eq!(parse_mode("invalid"), 0o644);
        assert_eq!(parse_mode(""), 0o644);
    }

    #[test]
    fn test_format_mode() {
        assert_eq!(format_mode(0o644), "644");
        assert_eq!(format_mode(0o755), "755");
    }

    #[test]
    fn test_save_and_make_writable_then_restore() {
        let temp = TempDir::new().unwrap();
        let file = temp.path().join("test.txt");
        std::fs::write(&file, "content").unwrap();

        // Make it read-only first
        set_readonly(&file).unwrap();
        assert!(std::fs::metadata(&file).unwrap().permissions().readonly());

        // Save and make writable
        let saved = save_and_make_writable(&file).unwrap();
        assert!(!std::fs::metadata(&file).unwrap().permissions().readonly());

        // Restore
        restore(&file, &saved).unwrap();
        assert!(std::fs::metadata(&file).unwrap().permissions().readonly());
    }

    #[test]
    fn test_set_readonly() {
        let temp = TempDir::new().unwrap();
        let file = temp.path().join("test.txt");
        std::fs::write(&file, "content").unwrap();

        set_readonly(&file).unwrap();
        assert!(std::fs::metadata(&file).unwrap().permissions().readonly());
    }

    #[cfg(unix)]
    #[test]
    fn test_set_mode() {
        use std::os::unix::fs::PermissionsExt;
        let temp = TempDir::new().unwrap();
        let file = temp.path().join("test.txt");
        std::fs::write(&file, "content").unwrap();

        set_mode(&file, 0o755).unwrap();
        let mode = std::fs::metadata(&file).unwrap().permissions().mode() & 0o777;
        assert_eq!(mode, 0o755);
    }

    #[test]
    fn test_restore_nonexistent_is_ok() {
        let saved = SavedPerms {
            #[cfg(unix)]
            mode: 0o644,
            #[cfg(not(unix))]
            readonly: false,
        };
        // Restoring a nonexistent file should not error (graceful)
        let result = restore(Path::new("/nonexistent/path/file.txt"), &saved);
        assert!(result.is_ok());
    }
}

//! Header-only veiling strategy.
//!
//! Shows only function/class signatures, hiding implementations.
//! This is useful for getting an overview of a codebase's public API.

use crate::error::Result;
use crate::parser::{ClassKind, ParsedFile, Symbol};
use crate::strategies::{get_lines, VeilStrategy};

/// Configuration for header mode veiling
#[derive(Debug, Clone)]
pub struct HeaderConfig {
    /// Include docstrings in output
    pub include_docstrings: bool,
    /// Max length for signatures (truncate if longer)
    pub max_signature_length: Option<usize>,
    /// Show class methods
    pub show_methods: bool,
    /// Show class properties
    pub show_properties: bool,
}

impl Default for HeaderConfig {
    fn default() -> Self {
        Self {
            include_docstrings: true,
            max_signature_length: None,
            show_methods: true,
            show_properties: false,
        }
    }
}

/// Find the largest byte index <= `index` that is a valid char boundary.
fn floor_char_boundary(s: &str, index: usize) -> usize {
    if index >= s.len() {
        return s.len();
    }
    let mut i = index;
    while i > 0 && !s.is_char_boundary(i) {
        i -= 1;
    }
    i
}

/// Veiling strategy that shows only signatures
pub struct HeaderStrategy {
    config: HeaderConfig,
}

impl HeaderStrategy {
    /// Create a new header strategy with default config
    pub fn new() -> Self {
        Self {
            config: HeaderConfig::default(),
        }
    }

    /// Create a new header strategy with custom config
    pub fn with_config(config: HeaderConfig) -> Self {
        Self { config }
    }

    /// Format a function signature for display
    fn format_function(&self, symbol: &Symbol, content: &str) -> String {
        let Symbol::Function {
            name,
            params,
            return_type,
            is_async,
            line_range,
            body_range,
            ..
        } = symbol
        else {
            return String::new();
        };

        // Get the signature (everything before the body)
        let signature_lines = if body_range.start() > line_range.start() {
            get_lines(content, line_range.start(), body_range.start() - 1)
        } else {
            // Fallback: construct from parts
            self.build_signature(name, params, return_type, *is_async)
        };

        // Truncate if needed
        if let Some(configured_max) = self.config.max_signature_length {
            let max_len = configured_max.max(3);
            if signature_lines.len() > max_len {
                let boundary = floor_char_boundary(&signature_lines, max_len.saturating_sub(3));
                return format!("{}...", &signature_lines[..boundary]);
            }
        }

        // Add placeholder for body
        let body_lines = body_range.len();
        format!(
            "{} {{ ... {} lines ... }}\n",
            signature_lines.trim_end(),
            body_lines
        )
    }

    /// Build a signature from parts when we can't extract from source
    fn build_signature(
        &self,
        name: &str,
        params: &[crate::parser::Param],
        return_type: &Option<String>,
        is_async: bool,
    ) -> String {
        let mut sig = String::new();

        if is_async {
            sig.push_str("async ");
        }

        sig.push_str(&format!("fn {name}("));
        sig.push_str(
            &params
                .iter()
                .map(|p| p.to_string())
                .collect::<Vec<_>>()
                .join(", "),
        );
        sig.push(')');

        if let Some(ret) = return_type {
            sig.push_str(&format!(" -> {ret}"));
        }

        sig
    }

    /// Format a class/struct for display
    fn format_class(&self, symbol: &Symbol, _content: &str) -> String {
        let Symbol::Class {
            name,
            kind,
            methods,
            properties,
            line_range,
            ..
        } = symbol
        else {
            return String::new();
        };

        let mut result = String::new();

        // Class declaration line
        let kind_str = match kind {
            ClassKind::Class => "class",
            ClassKind::Struct => "struct",
            ClassKind::Trait => "trait",
            ClassKind::Interface => "interface",
            ClassKind::Enum => "enum",
        };

        result.push_str(&format!("{kind_str} {name} {{\n"));

        // Properties (if enabled)
        if self.config.show_properties {
            for prop in properties {
                if let Some(ref ty) = prop.type_annotation {
                    result.push_str(&format!("    {}: {},\n", prop.name, ty));
                } else {
                    result.push_str(&format!("    {},\n", prop.name));
                }
            }
        }

        // Methods (if enabled)
        if self.config.show_methods {
            for method in methods {
                if let Symbol::Function {
                    name,
                    params,
                    return_type,
                    is_async,
                    ..
                } = method
                {
                    let sig = self.build_signature(name, params, return_type, *is_async);
                    result.push_str(&format!("    {sig} {{ ... }}\n"));
                }
            }
        }

        // Show body size
        result.push_str(&format!("    // ... {} lines ...\n", line_range.len()));
        result.push_str("}\n");

        result
    }
}

impl Default for HeaderStrategy {
    fn default() -> Self {
        Self::new()
    }
}

impl VeilStrategy for HeaderStrategy {
    fn veil_file(&self, content: &str, parsed: &ParsedFile) -> Result<String> {
        let mut result = String::new();
        let mut last_end = 1; // 1-indexed line tracking

        // Sort symbols by line number to process in order
        let mut symbols: Vec<_> = parsed.symbols.iter().collect();
        symbols.sort_by_key(|s| s.line_range().start());

        for symbol in symbols {
            let line_range = symbol.line_range();

            // Add content before this symbol
            if line_range.start() > last_end {
                let before = get_lines(content, last_end, line_range.start() - 1);
                if !before.trim().is_empty() {
                    result.push_str(&before);
                    result.push('\n');
                }
            }

            // Add veiled version of symbol
            let veiled = match symbol {
                Symbol::Function { .. } => self.format_function(symbol, content),
                Symbol::Class { .. } => self.format_class(symbol, content),
                _ => String::new(),
            };
            result.push_str(&veiled);

            last_end = line_range.end() + 1;
        }

        // Add remaining content after last symbol
        let total_lines = content.lines().count();
        if last_end <= total_lines {
            let after = get_lines(content, last_end, total_lines);
            if !after.trim().is_empty() {
                result.push_str(&after);
                result.push('\n');
            }
        }

        Ok(result)
    }

    fn description(&self) -> &'static str {
        "Shows only function and class signatures, hiding implementations"
    }
}

