            is_async: false,
            attributes: vec![],
        };

        let result = strategy.format_function(&symbol, "fn ab() {}");
        // "fn ab()" is exactly 7 chars = max_len, so should NOT truncate.
        // Non-truncated output: "fn ab() { ... 1 lines ... }\n"
